CREATE TABLE `bookings` (
  `id` int(11) UNSIGNED NOT NULL,
  `company_id` int(11) NOT NULL DEFAULT 1,
  `ref_no` varchar(20) NOT NULL,
  `source` enum('Supplier','Direct','Partner','Website','Call Centre') NOT NULL DEFAULT 'Supplier',
  `website_name` varchar(150) DEFAULT NULL,
  `product_name` varchar(150) DEFAULT NULL,
  `discount` decimal(10,2) DEFAULT NULL,
  `airport` enum('LHR','LGW','STN','LTN','MAN','BHX') NOT NULL,
  `service_type` enum('meet greet','park ride') NOT NULL,
  `customer_name` varchar(100) NOT NULL,
  `contact_no` varchar(20) DEFAULT NULL,
  `customer_email` varchar(150) DEFAULT NULL,
  `booked_on` datetime NOT NULL,
  `dropoff_datetime` datetime NOT NULL,
  `return_datetime` datetime NOT NULL,
  `vehicle_reg_no` varchar(15) DEFAULT NULL,
  `terminal` varchar(32) DEFAULT NULL,
  `flight` varchar(20) DEFAULT NULL,
  `driver` varchar(100) DEFAULT NULL,
  `yard` varchar(100) DEFAULT NULL,
  `make_model` varchar(120) DEFAULT NULL,
  `no_of_days` int(10) UNSIGNED DEFAULT NULL,
  `quote_price` decimal(10,2) DEFAULT NULL,
  `paid_price` decimal(10,2) DEFAULT NULL,
  `comment` text DEFAULT NULL,
  `price` decimal(10,2) NOT NULL DEFAULT 0.00,
  `status` enum('Active','Cancelled','Completed','No Show','Refunded','pending') NOT NULL DEFAULT 'pending',
  `notes` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `airport_alias` text DEFAULT NULL,
  `booking_type` enum('Drop Off','Return','Both') DEFAULT 'Drop Off',
  `supplier_name` varchar(255) DEFAULT NULL,
  `color` varchar(50) DEFAULT NULL,
  `model` varchar(20) DEFAULT NULL,
  `flexibility` varchar(50) DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Triggers `bookings`
--
DELIMITER $$
CREATE TRIGGER `update_supplier_count` AFTER INSERT ON `bookings` FOR EACH ROW UPDATE suppliers s
SET s.bookings_count = (
    SELECT COUNT(*) FROM bookings WHERE supplier_name = NEW.supplier_name
)
WHERE s.supplier_name = NEW.supplier_name
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `update_website_count` AFTER INSERT ON `bookings` FOR EACH ROW UPDATE website_settings w
SET w.bookings_count = (
    SELECT COUNT(*) FROM bookings WHERE website_name = NEW.website_name
)
WHERE w.website_name = NEW.website_name
$$
DELIMITER ;

