--
-- Triggers `parking_bookings`
--
DELIMITER $$
CREATE TRIGGER `trg_set_ref_no_before_insert` BEFORE INSERT ON `parking_bookings` FOR EACH ROW BEGIN
    -- Only generate ref_no if status is Active AND ref_no is NULL
    IF NEW.status = 'Active' AND (NEW.ref_no IS NULL OR NEW.ref_no = '') THEN
        SET NEW.ref_no = CONCAT(
            'TPR-', 
            NEW.company_id, -- Inject company ID into the ref string to ensure no collision
            '-',
            LPAD((SELECT AUTO_INCREMENT
                  FROM information_schema.TABLES
                  WHERE TABLE_SCHEMA = DATABASE()
                  AND TABLE_NAME = 'parking_bookings'), 6, '0')
        );
    END IF;
END
$$
DELIMITER ;

-- --------------------------------------------------------

--
-- Table structure for table `parking_products`
--

CREATE TABLE `parking_products` (
  `id` int(11) NOT NULL,
  `company_id` int(11) NOT NULL DEFAULT 1,
  `airport_name` varchar(50) NOT NULL,
  `service_provider` varchar(150) NOT NULL,
  `image_url` varchar(255) DEFAULT NULL,
  `product_name` varchar(150) NOT NULL,
  `airport_number` varchar(50) DEFAULT NULL,
  `airport_duty_number` varchar(50) DEFAULT NULL,
  `booking_email` varchar(150) DEFAULT NULL,
  `airport_charges` decimal(10,2) DEFAULT 0.00,
  `operational_from` time NOT NULL,
  `operational_to` time NOT NULL,
  `book_short_hours` int(11) DEFAULT 0,
  `edit_short_hours` int(11) DEFAULT 0,
  `cancel_short_hours` int(11) DEFAULT 0,
  `promocodes_applicable` enum('Yes','No') DEFAULT 'No',
  `commission` decimal(5,2) DEFAULT 0.00,
  `product_extra` varchar(255) DEFAULT NULL,
  `nonflex` enum('Refundable','Non-Refundable','Semi-Flexible') DEFAULT 'Non-Refundable',
  `service_type` enum('Meet & Greet','Park & Ride','Indoor Valet','Other') NOT NULL,
  `recommended` varchar(255) DEFAULT NULL,
  `product_description` text DEFAULT NULL,
